    "\u05d4\u05d1\u05e8\u05db\u05d4 \u05de\u05e9\u05d1\u05d7\u05ea \u05d0\u05ea \u05d4' \u05e2\u05dc \u05d1\u05e8\u05d9\u05d0\u05ea "
    "\"\u05e2\u05e6\u05d9\u05dd \u05d8\u05d5\u05d1\u05d9\u05dd \u05dc\u05d4\u05e0\u05d5\u05ea \u05d1\u05d4\u05dd \u05d1\u05e0\u05d9 \u05d0\u05d3\u05dd\" \u2014 "
