    "\u05dc\u05db\u05ea\u05d7\u05d9\u05dc\u05d4 (\u05d0\u05d9\u05d3\u05d0\u05dc): \u05d4\u05e2\u05e5 \u05e2\u05d1\u05e8 \u05d0\u05ea \u05e9\u05dc\u05d1 \u05d4\u05e2\u05dc\u05d9\u05dd \u05d1\u05dc\u05d1\u05d3 "
