    "\u2022 \u05d0\u05d7\u05e8\u05d9 \u05e0\u05e9\u05d9\u05e8\u05ea \u05d4\u05d4\u05ea\u05e4\u05ea\u05dc\u05d5\u05ea \u05d5\u05d4\u05ea\u05d7\u05dc\u05ea \u05d4\u05e4\u05e8\u05d9 \u2014 "
